// Code Generated by Sidekick is for learning and experimentation purposes only.
/**
 * Enhanced Network Debugging for FHIR Requests
 * Intercepts and logs all network activity with full details
 */

const NetworkDebugger = {
    requests: [],
    
    /**
     * Initialize network debugging by intercepting fetch
     */
    init() {
        console.log('=== Network Debugger Initialized ===');
        
        // Store original fetch
        const originalFetch = window.fetch;
        
        // Override fetch to add debugging
        window.fetch = async function(...args) {
            const requestId = Date.now() + '-' + Math.random().toString(36).substr(2, 9);
            const startTime = performance.now();
            
            // Parse request details
            const url = typeof args[0] === 'string' ? args[0] : args[0].url;
            const options = args[1] || {};
            const method = options.method || 'GET';
            
            console.log(`\n=== 🌐 Network Request [${requestId}] ===`);
            console.log(`Method: ${method}`);
            console.log(`URL: ${url}`);
            
            // Log headers
            console.log('Headers:', options.headers || 'None');
            
            // Check for Authorization header
            if (options.headers) {
                const headers = new Headers(options.headers);
                const authHeader = headers.get('Authorization');
                if (authHeader) {
                    console.log(`✓ Authorization Header Present: ${authHeader.substring(0, 30)}...`);
                } else {
                    console.warn('⚠️ No Authorization Header Found!');
                }
            } else {
                console.warn('⚠️ No Headers in Request!');
            }
            
            // Log body if present
            if (options.body) {
                console.log('Request Body:', options.body);
            }
            
            const requestLog = {
                id: requestId,
                method: method,
                url: url,
                headers: options.headers,
                body: options.body,
                startTime: new Date().toISOString(),
                status: null,
                statusText: null,
                responseHeaders: null,
                responseBody: null,
                error: null,
                duration: null
            };
            
            try {
                // Make the actual request
                const response = await originalFetch(...args);
                const endTime = performance.now();
                const duration = Math.round(endTime - startTime);
                
                console.log(`\n=== 📥 Network Response [${requestId}] ===`);
                console.log(`Status: ${response.status} ${response.statusText}`);
                console.log(`Duration: ${duration}ms`);
                console.log(`OK: ${response.ok}`);
                
                // Log response headers
                console.log('Response Headers:');
                response.headers.forEach((value, key) => {
                    console.log(`  ${key}: ${value}`);
                });
                
                // Clone response to read body without consuming it
                const clonedResponse = response.clone();
                
                // Try to read response body
                let responseBody = null;
                let responseText = null;
                try {
                    responseText = await clonedResponse.text();
                    console.log('Response Body (first 500 chars):', responseText.substring(0, 500));
                    
                    // Try to parse as JSON
                    try {
                        responseBody = JSON.parse(responseText);
                        console.log('Parsed Response:', responseBody);
                    } catch (e) {
                        console.log('Response is not JSON');
                        responseBody = responseText;
                    }
                } catch (e) {
                    console.error('Could not read response body:', e);
                }
                
                // Update request log
                requestLog.status = response.status;
                requestLog.statusText = response.statusText;
                requestLog.ok = response.ok;
                requestLog.responseHeaders = Object.fromEntries(response.headers.entries());
                requestLog.responseBody = responseBody;
                requestLog.duration = duration;
                
                NetworkDebugger.requests.push(requestLog);
                
                // Check for common issues
                if (!response.ok) {
                    console.error(`❌ Request Failed: ${response.status} ${response.statusText}`);
                    
                    if (response.status === 401) {
                        console.error('🔐 Authorization Error - Token may be invalid or expired');
                    } else if (response.status === 403) {
                        console.error('🚫 Forbidden - You may not have permission to access this resource');
                    } else if (response.status === 404) {
                        console.error('❓ Not Found - The resource does not exist');
                    } else if (response.status === 0) {
                        console.error('🌐 Network Error - This might be a CORS issue');
                    }
                }
                
                return response;
                
            } catch (error) {
                const endTime = performance.now();
                const duration = Math.round(endTime - startTime);
                
                console.error(`\n=== ❌ Network Error [${requestId}] ===`);
                console.error(`Error: ${error.message}`);
                console.error(`Error Type: ${error.name}`);
                console.error(`Duration: ${duration}ms`);
                console.error('Full Error:', error);
                
                // Diagnose common network errors
                if (error.message.includes('Failed to fetch') || error.message.includes('Network request failed')) {
                    console.error('\n🔍 Possible Causes:');
                    console.error('  1. CORS Error - Server does not allow cross-origin requests');
                    console.error('  2. Network Connectivity Issue');
                    console.error('  3. Server is unreachable or down');
                    console.error('  4. Invalid URL');
                    console.error('  5. SSL/TLS certificate issues');
                    console.error('\n💡 Check the browser Network tab for more details');
                }
                
                // Update request log
                requestLog.error = {
                    message: error.message,
                    name: error.name,
                    stack: error.stack
                };
                requestLog.duration = duration;
                
                NetworkDebugger.requests.push(requestLog);
                
                // Re-throw the error
                throw error;
            }
        };
        
        console.log('✓ Fetch interceptor installed');
    },
    
    /**
     * Get all logged requests
     */
    getRequests() {
        return this.requests;
    },
    
    /**
     * Get failed requests only
     */
    getFailedRequests() {
        return this.requests.filter(r => r.error || !r.ok);
    },
    
    /**
     * Clear request log
     */
    clear() {
        this.requests = [];
        console.log('Network debug log cleared');
    },
    
    /**
     * Export debug data
     */
    export() {
        return {
            totalRequests: this.requests.length,
            failedRequests: this.getFailedRequests().length,
            requests: this.requests.map(r => ({
                ...r,
                // Truncate large response bodies for readability
                responseBody: typeof r.responseBody === 'string' && r.responseBody.length > 1000 ?
                    r.responseBody.substring(0, 1000) + '... (truncated)' :
                    r.responseBody
            }))
        };
    }
};

// Make it globally available
window.NetworkDebugger = NetworkDebugger;
